/*
  Reset fictional CRM customer data and reassign customer IDs from 1.
  Generated by scripts/generate-customer-data-package.ps1.
*/
USE MarriageCrm;
GO
SET XACT_ABORT ON;
BEGIN TRANSACTION;
DELETE FROM dbo.matching_history;
DELETE FROM dbo.contracts;
DELETE FROM dbo.consulting_notes;
DELETE FROM dbo.customers;
IF EXISTS (SELECT 1 FROM sys.check_constraints WHERE name = N'CK_customers_gender')
    ALTER TABLE dbo.customers DROP CONSTRAINT CK_customers_gender;
ALTER TABLE dbo.customers WITH CHECK ADD CONSTRAINT CK_customers_gender CHECK (gender IN (N'남성', N'여성', N'비공개'));
IF EXISTS (SELECT 1 FROM sys.check_constraints WHERE name = N'CK_contracts_membership_level')
    ALTER TABLE dbo.contracts DROP CONSTRAINT CK_contracts_membership_level;
IF EXISTS (SELECT 1 FROM sys.check_constraints WHERE name = N'CK_contracts_contract_status')
    ALTER TABLE dbo.contracts DROP CONSTRAINT CK_contracts_contract_status;
ALTER TABLE dbo.contracts WITH CHECK ADD CONSTRAINT CK_contracts_membership_level CHECK (membership_level IN (N'스탠다드', N'프리미엄'));
ALTER TABLE dbo.contracts WITH CHECK ADD CONSTRAINT CK_contracts_contract_status CHECK (contract_status IN (N'유효', N'만료', N'해지'));
DBCC CHECKIDENT (N'dbo.customers', RESEED, 0) WITH NO_INFOMSGS;
DBCC CHECKIDENT (N'dbo.consulting_notes', RESEED, 0) WITH NO_INFOMSGS;
DBCC CHECKIDENT (N'dbo.contracts', RESEED, 0) WITH NO_INFOMSGS;
DBCC CHECKIDENT (N'dbo.matching_history', RESEED, 0) WITH NO_INFOMSGS;
SET IDENTITY_INSERT dbo.customers ON;
SET IDENTITY_INSERT dbo.customers OFF;
SET IDENTITY_INSERT dbo.consulting_notes ON;
SET IDENTITY_INSERT dbo.consulting_notes OFF;
SET IDENTITY_INSERT dbo.contracts ON;
SET IDENTITY_INSERT dbo.contracts OFF;
SET IDENTITY_INSERT dbo.matching_history ON;
SET IDENTITY_INSERT dbo.matching_history OFF;
COMMIT TRANSACTION;
GO
SELECT MIN(id) AS min_customer_id, MAX(id) AS max_customer_id, COUNT(*) AS customer_count FROM dbo.customers;
SELECT TOP (10) id, name, customer_grade FROM dbo.customers ORDER BY id;
